const raw = $input.first().json;
const body = (raw.body !== undefined && typeof raw.body === 'object') ? raw.body : raw;

let payload, artifactId, trackerId, projectId, action;

if (body.payload !== undefined) {
  const p = typeof body.payload === 'string' ? JSON.parse(body.payload) : body.payload;
  payload = p;
  artifactId = p.current?.id || p.artifact_id;
  trackerId = p.current?.tracker?.id || p.tracker_id;
  projectId = p.current?.project?.id || p.project?.id || p.project_id;
  action = p.action || 'artifact:updated';
} else if (body.artifact !== undefined) {
  payload = { current: body.artifact, project: body.project, user: body.user, action: body.action };
  artifactId = body.artifact.id;
  trackerId = body.artifact.tracker?.id;
  projectId = body.project?.id;
  action = body.action || 'artifact:created';
} else {
  throw new Error('Unrecognized Tuleap payload format');
}

if (!trackerId) throw new Error('No tracker ID found in payload');

let valuesMap = {};
const values = payload.current?.values || payload.values || [];
for (const v of values) {
  const key = v.field_name || v.label || v.name || `field_${v.field_id}`;
  const val = v.value !== undefined ? v.value :
              v.bind_value_ids ? v.bind_value_ids :
              v.links ? v.links :
              v.content || null;
  valuesMap[key] = val;
}

return {
  json: {
    tracker_id: trackerId,
    project_id: projectId,
    action: action,
    artifact: {
      id: artifactId,
      uri: `${$env.TULEAP_BASE_URL || 'https://tuleap.windinfosys.com'}/plugins/tracker/?aid=${artifactId}`,
      values: values
    },
    raw_payload: payload,
    normalized_values: valuesMap
  }
};
